def solve_job_sequencing(jobs):
    jobs.sort(key=lambda x: x[2], reverse=True)

    max_deadline = 0
    for job_id, deadline, profit in jobs:
        if deadline > max_deadline:
            max_deadline = deadline

    slots = [None] * (max_deadline + 1)

    total_profit = 0

    for job_id, deadline, profit in jobs:
        for i in range(min(deadline, max_deadline), 0, -1):
            if slots[i] is None:
                slots[i] = job_id
                total_profit += profit
                break

    final_sequence_in_slot_order = []
    for i in range(1, max_deadline + 1):
        if slots[i] is not None:
            final_sequence_in_slot_order.append(slots[i])

    return final_sequence_in_slot_order, total_profit
